1. import { db } from "@/db";
2. import { links } from "@/db/schema";
3. import { eq, desc, and } from "drizzle-orm";
4. 
5. export async function getLinksByUserId(userId: string) {
6.   return db
7.     .select()
8.     .from(links)
9.     .where(eq(links.userId, userId))
10.     .orderBy(desc(links.createdAt));
11. }
12. 
13. export async function createLink(data: {
14.   userId: string;
15.   shortCode: string;
16.   url: string;
17. }) {
18.   const [link] = await db
19.     .insert(links)
20.     .values({
21.       userId: data.userId,
22.       shortCode: data.shortCode,
23.       url: data.url,
24.     })
25.     .returning();
26.   return link;
27. }
28. 
29. export async function updateLink(data: {
30.   id: string;
31.   userId: string;
32.   shortCode: string;
33.   url: string;
34. }) {
35.   const [link] = await db
36.     .update(links)
37.     .set({
38.       shortCode: data.shortCode,
39.       url: data.url,
40.       updatedAt: new Date(),
41.     })
42.     .where(and(eq(links.id, data.id), eq(links.userId, data.userId)))
43.     .returning();
44.   return link;
45. }
46. 
47. export async function deleteLink(data: { id: string; userId: string }) {
48.   const [link] = await db
49.     .delete(links)
50.     .where(and(eq(links.id, data.id), eq(links.userId, data.userId)))
51.     .returning();
52.   return link;
53. }
54. 
55. export async function getLinkByShortCode(shortCode: string) {
56.   const [link] = await db
57.     .select()
58.     .from(links)
59.     .where(eq(links.shortCode, shortCode))
60.     .limit(1);
61.   return link;
62. }
